// Parse input and build the MCP write_file payload
const body = $input.first().json.body;
const planText = body?.plan || (typeof body === 'string' ? body : JSON.stringify(body));
const filename = body?.filename || 'unnamed-plan';
const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);

// Build MCP JSON-RPC payload for write_file
const mcpPayload = {
  jsonrpc: "2.0",
  id: 1,
  method: "tools/call",
  params: {
    name: "write_file",
    arguments: {
      path: "/host/opt/stacks/YOUR_PROJECT/.tmp-plan-check.md",
      content: planText
    }
  }
};

return [{ json: { mcpPayload, planText, filename, timestamp } }];

// Call MCP via supergateway Docker network - keep SSE stream open for result
const http = require('http');

function postMsg(sessionId, body) {
  return new Promise((resolve, reject) => {
    const req = http.request({
      hostname: 'supergateway-filesystem', port: 8000,
      path: `/message?sessionId=${sessionId}`,
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    }, (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => resolve(data));
    });
    req.on('error', reject);
    req.setTimeout(10000, () => { req.destroy(); });
    if (body) req.write(typeof body === 'string' ? body : JSON.stringify(body));
    req.end();
  });
}

// Open persistent SSE connection and collect ALL events
const sseData = await new Promise((resolve, reject) => {
  let collected = '';
  let sessionId = null;
  let commandSent = false;
  let resultReceived = false;

  const req = http.request({
    hostname: 'supergateway-filesystem', port: 8000,
    path: '/sse', method: 'GET',
    headers: { 'Accept': 'text/event-stream' }
  }, (res) => {
    // Set a generous overall timeout
    const overallTimer = setTimeout(() => {
      req.destroy();
      resolve({ collected, sessionId, timedOut: true });
    }, 175000);

    res.on('data', async (chunk) => {
      collected += chunk.toString();

      // Step 1: Extract sessionId from the endpoint event
      if (!sessionId) {
        const match = collected.match(/sessionId=([a-f0-9-]+)/);
        if (match) {
          sessionId = match[1];

          // Step 2: Initialize MCP session
          try {
            await postMsg(sessionId, {
              jsonrpc: '2.0', id: 0, method: 'initialize',
              params: { protocolVersion: '2025-11-25', capabilities: {},
                clientInfo: { name: 'n8n', version: '1.0' } }
            });
            await new Promise(r => setTimeout(r, 500));
            await postMsg(sessionId, { jsonrpc: '2.0', method: 'notifications/initialized' });
            await new Promise(r => setTimeout(r, 300));
          } catch (e) { /* init errors are ok */ }
        }
      }

      // Step 3: After init response arrives, send the Claude Code command
      if (sessionId && !commandSent && collected.includes('"id":0') && collected.includes('"result"')) {
        commandSent = true;

        // -----------------------------------------------------------------------
        // CUSTOMIZE THIS PROMPT to match your project's architecture.
        // The example below checks a TypeScript/Drizzle/Better Auth/Expo stack.
        // Adapt the file paths, frameworks, and validation rules for your project.
        // -----------------------------------------------------------------------
        const prompt = 'Read .tmp-plan-check.md which is a development plan to validate against this codebase. Analyze it:\\n1. Read src/db/schema.ts - check every table/column the plan mentions exists. Flag new migrations needed.\\n2. Grep src/routes/*.ts for endpoints. Verify API routes the plan mentions exist.\\n3. Read src/lib/auth.ts - check plan respects auth hooks and session config.\\n4. Verify new files go in correct dirs.\\n5. MOBILE CONFIG PROTECTION: Read app.json and/or app.config.ts if they exist - record the current mobile bundle IDs, scheme, splash, icons, permissions, and plugin configs. Check if the plan touches any files that affect Expo/React Native mobile config (app.json, app.config.ts, eas.json, babel.config.js, metro.config.js, package.json expo field, native/ or ios/ or android/ dirs). If so, flag MOBILE_INTERFERENCE: list every mobile config key/value that must be preserved unchanged and confirm the plan does not alter them. If the plan adds packages, check they have no native modules that require a new EAS build.\\nOutput markdown sections: Aligned, Warnings, Misaligned (plan says vs exists vs fix), Missing from Plan, New Infrastructure, MOBILE CONFIG STATUS (Safe / Needs Review - list every affected mobile config key). Be precise.';

        const cmd = `su - YOUR_USER -c 'CLAUDE_BIN=$(ls -d /home/YOUR_USER/.vscode-server/extensions/anthropic.claude-code-*-linux-x64/resources/native-binary/claude 2>/dev/null | sort -V | tail -1) && cd /opt/stacks/YOUR_PROJECT && $CLAUDE_BIN --print "${prompt}" --model sonnet --output-format text --max-turns 15 --allowed-tools "Read Bash(grep:*) Bash(cat:app.json) Bash(cat:app.config.ts) Bash(cat:eas.json) Bash(cat:babel.config.js) Bash(cat:metro.config.js)" 2>&1'`;

        try {
          await postMsg(sessionId, {
            jsonrpc: '2.0', id: 2,
            method: 'tools/call',
            params: { name: 'execute_command', arguments: { command: cmd, timeout: 180000 } }
          });
        } catch (e) { /* send errors ok - response comes on SSE */ }
      }

      // Step 4: Check if we got the Claude Code result (id: 2)
      if (commandSent && !resultReceived && collected.includes('"id":2') && collected.includes('"result"')) {
        const lastDataIdx = collected.lastIndexOf('data: {');
        if (lastDataIdx > -1) {
          const remainder = collected.substring(lastDataIdx);
          if (remainder.includes('"stdout"') || remainder.includes('"isError"')) {
            resultReceived = true;
            clearTimeout(overallTimer);
            req.destroy();
            resolve({ collected, sessionId, timedOut: false });
          }
        }
      }
    });

    res.on('end', () => {
      clearTimeout(overallTimer);
      resolve({ collected, sessionId, timedOut: false });
    });
  });

  req.on('error', (e) => {
    if (e.code !== 'ECONNRESET') reject(e);
  });
  req.end();
});

// Parse out the result from the collected SSE data
let resultJson = '';
const lines = sseData.collected.split('\n');
for (let i = lines.length - 1; i >= 0; i--) {
  if (lines[i].startsWith('data: {') && lines[i].includes('"id":2')) {
    resultJson = lines[i].substring(6);
    break;
  }
}

return [{ json: {
  result: resultJson || sseData.collected,
  sessionId: sseData.sessionId,
  timedOut: sseData.timedOut
} }];

// Parse response from Run Claude Code node
const raw = $('Run Claude Code').first().json;
let analysis = '';

try {
  let resultData = raw.result || raw;
  if (typeof resultData === 'string') {
    try { resultData = JSON.parse(resultData); } catch {}
  }
  if (resultData?.result?.content?.[0]?.text) {
    const execOutput = resultData.result.content[0].text;
    try {
      const parsed = JSON.parse(execOutput);
      analysis = parsed.stdout || parsed.text || execOutput;
    } catch { analysis = execOutput; }
  } else if (resultData?.error) {
    analysis = `Error: ${JSON.stringify(resultData.error)}`;
  } else if (typeof resultData === 'string') {
    const stdoutMatch = resultData.match(/"stdout"\s*:\s*"((?:[^"\\]|\\.)*)"/);
    if (stdoutMatch) analysis = JSON.parse('"' + stdoutMatch[1] + '"');
    else analysis = resultData;
  } else {
    analysis = JSON.stringify(resultData, null, 2);
  }
} catch (e) {
  analysis = 'Error parsing: ' + e.message;
}

const meta = $('Parse Input').first().json;
const now = new Date().toLocaleString('en-US', { timeZone: 'Your/Timezone' });

return [{ json: { report: `# Plan Alignment Report

**Plan:** ${meta.filename}  
**Checked:** ${now}  
**Engine:** Claude Code (Max) → Sonnet  
**Project:** /opt/stacks/YOUR_PROJECT

---

${analysis}

---

*Generated by n8n Plan Alignment Workflow v1.0*
` } }];

// Build Gotify notification from raw Claude Code output
const raw = $input.first().json;
const meta = $('Parse Input').first().json;

// Parse the Claude Code result
let analysis = '';
try {
  let resultData = raw.result || raw;
  if (typeof resultData === 'string') {
    try { resultData = JSON.parse(resultData); } catch {}
  }
  if (resultData?.result?.content?.[0]?.text) {
    const execOutput = resultData.result.content[0].text;
    try {
      const parsed = JSON.parse(execOutput);
      analysis = parsed.stdout || parsed.text || execOutput;
    } catch { analysis = execOutput; }
  } else if (typeof resultData === 'string') {
    const stdoutMatch = resultData.match(/"stdout"\s*:\s*"((?:[^"\\]|\\.)*)"/);
    if (stdoutMatch) analysis = JSON.parse('"' + stdoutMatch[1] + '"');
    else analysis = resultData;
  } else {
    analysis = JSON.stringify(resultData, null, 2);
  }
} catch (e) { analysis = 'Parse error: ' + e.message; }

// Count issues by scanning the analysis text
const countMatches = (pattern) => (analysis.match(pattern) || []).length;
const hasCritical = /CRITICAL|BLOCKED BY DESIGN|MOBILE_INTERFERENCE/i.test(analysis);
const misalignedCount = countMatches(/❌|Misaligned|Does not exist|BLOCKED/gi);
const warningCount = countMatches(/⚠️|Warning|already exists|duplicate|conflict/gi);

// Determine severity
let severity, priority, emoji;
if (hasCritical || misalignedCount > 3) {
  severity = 'CRITICAL'; priority = 8; emoji = '🚨';
} else if (misalignedCount > 0) {
  severity = 'Issues Found'; priority = 5; emoji = '⚠️';
} else if (warningCount > 0) {
  severity = 'Warnings Only'; priority = 3; emoji = '📋';
} else {
  severity = 'All Clear'; priority = 1; emoji = '✅';
}

// Extract key misaligned items
const issueLines = analysis.split('\n')
  .filter(l => /^\| \*\*/.test(l.trim()) || /^- ❌/.test(l.trim()) || /Does not exist/.test(l) || /BLOCKED/.test(l))
  .map(l => l.replace(/^\|?\s*\*?\*?/, '').replace(/\*?\*?\s*\|.*$/, '').trim())
  .filter(l => l.length > 10 && l.length < 200)
  .slice(0, 5);

const title = `${emoji} Plan Check: ${meta.filename}`;
const now = new Date().toLocaleString('en-US', { timeZone: 'Your/Timezone' });

let message = `## ${severity}\n\n`;
message += `**Plan:** \`${meta.filename}\`\n`;
message += `**Checked:** ${now}\n\n`;

if (issueLines.length > 0) {
  message += `### Key Findings\n\n`;
  issueLines.forEach(item => {
    message += `- ${item}\n`;
  });
  message += '\n';
}

if (hasCritical) {
  const mobileConflict = /MOBILE_INTERFERENCE/i.test(analysis);
  const authConflict = /CRITICAL|BLOCKED BY DESIGN/i.test(analysis);
  if (authConflict) message += `\n🔴 **Auth/Design Conflict** — Plan conflicts with protected hooks or fields\n`;
  if (mobileConflict) message += `\n📱 **Mobile Config Conflict** — Plan interferes with Expo/React Native config\n`;
}

message += `\n---\n_Full report returned in webhook response_`;

return [{ json: { title, message, priority } }];
